
-- Step 1: Drop the name-only unique constraint that prevents tenant-specific profiles
ALTER TABLE public.access_profiles DROP CONSTRAINT access_profiles_name_unique;

-- Step 2: Add a composite unique constraint scoped to tenant_id
ALTER TABLE public.access_profiles ADD CONSTRAINT access_profiles_name_tenant_unique UNIQUE (name, tenant_id);

