-- Step 4: Update Mica admin users to use the tenant-specific Admin profile
UPDATE public.profiles 
SET profile_id = (
  SELECT id FROM public.access_profiles 
  WHERE name = 'Admin' AND tenant_id = 'bf9bb59f-31a7-4c11-b23d-7a1d67d65af1'
  LIMIT 1
)
WHERE tenant_id = 'bf9bb59f-31a7-4c11-b23d-7a1d67d65af1' 
  AND role = 'admin';
